// Parse and validate webhook payload
const body = $input.first().json.body;

// Extract lead information with defaults
const lead = {
  external_id: body.lead_id || generateId(),
  name: body.name?.trim() || '',
  email: body.email?.toLowerCase().trim() || '',
  phone_number: normalizePhone(body.phone || ''),
  phone_country_code: body.country_code || 'US',
  source_channel: body.source || 'website',
  procedures_interested: Array.isArray(body.procedures) ? body.procedures : [body.procedure || ''],
  estimated_budget_min: parseInt(body.budget_min) || null,
  estimated_budget_max: parseInt(body.budget_max) || null,
  timeline: body.timeline || 'unknown',
  age_range: body.age_range || null,
  language_preference: body.language || 'english',
  consent_call: body.consent_call === true,
  consent_sms: body.consent_sms === true,
  consent_email: body.consent_email === true,
  notes: body.notes?.substring(0, 500) || '',
  timestamp: new Date().toISOString(),
  metadata: {
    user_agent: body.user_agent || '',
    ip_address: body.ip_address || '',
    referrer: body.referrer || '',
    utm_source: body.utm_source || '',
    utm_campaign: body.utm_campaign || '',
    utm_medium: body.utm_medium || ''
  }
};

function generateId() {
  return 'lead_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
}

function normalizePhone(phone) {
  if (!phone) return '';
  // Remove non-digit characters
  return phone.replace(/\D/g, '');
}

// Validation
if (!lead.email && !lead.phone_number) {
  throw new Error('Either email or phone number is required');
}

if (!lead.name || lead.name.length < 2) {
  throw new Error('Valid name is required');
}

return { lead, raw_body: body };

const lead = $input.first().json.lead;

// Determine lead score based on available information
let score = 30; // base score

if (lead.email) score += 10;
if (lead.phone_number) score += 10;
if (lead.procedures_interested.length > 0 && lead.procedures_interested[0]) score += 10;

if (lead.estimated_budget_min && lead.estimated_budget_min >= 3000) score += 25;
else if (lead.estimated_budget_min && lead.estimated_budget_min >= 1500) score += 15;
else if (lead.estimated_budget_min) score += 5;

if (lead.timeline === 'immediate' || lead.timeline === 'within_1_month') score += 15;
else if (lead.timeline === 'within_3_months') score += 10;
else if (lead.timeline === 'within_6_months') score += 5;

if (lead.source_channel === 'chat' || lead.source_channel === 'form') score += 5;
if (lead.consent_call || lead.consent_sms) score += 5;

// Determine initial qualification status
let qualification = 'cold';
if (score >= 80) qualification = 'hot';
else if (score >= 50) qualification = 'warm';
else if (score >= 30) qualification = 'cool';

// Determine timezone from phone or use default
let timezone = 'America/Chicago';
if (lead.phone_country_code === 'US') {
  const areaCode = lead.phone_number?.substring(0, 3);
  const tzMap = {
    '201': 'America/New_York',
    '212': 'America/New_York',
    '310': 'America/Los_Angeles',
    '415': 'America/Los_Angeles',
    '512': 'America/Chicago',
    '305': 'America/New_York',
    '786': 'America/New_York'
  };
  timezone = tzMap[areaCode] || 'America/Chicago';
}

return {
  ...lead,
  lead_score: Math.min(100, score),
  qualification_status: qualification,
  timezone: timezone,
  enriched_at: new Date().toISOString()
};

const lead = $input.first().json;

// Determine next action based on lead score and qualifications
let action = 'email_nurture';
let route_to = 'none';
let priority = 'low';

if (lead.lead_score >= 80 && lead.consent_call) {
  // HOT: Route to voice agent for immediate call
  action = 'route_to_voice_agent';
  route_to = 'retell_voice_agent';
  priority = 'critical';
} else if (lead.lead_score >= 70 && lead.consent_sms) {
  // WARM: Route to SMS first
  action = 'route_to_sms';
  route_to = 'twilio_sms';
  priority = 'high';
} else if (lead.lead_score >= 50 && lead.consent_email) {
  // WARM: Route to email with callback offer
  action = 'route_to_email';
  route_to = 'sendgrid_callback_offer';
  priority = 'medium';
} else if (lead.consent_email) {
  // COOL/COLD: Route to automated nurture sequence
  action = 'route_to_automation';
  route_to = 'automated_nurture';
  priority = 'low';
} else {
  // No consent: hold for consent acquisition
  action = 'hold_for_consent';
  route_to = 'none';
  priority = 'low';
}

return {
  ...lead,
  next_action: action,
  route_to: route_to,
  priority: priority,
  ready_for_routing: route_to !== 'none'
};

