    {
      "id": "condition_route_email",
      "type": "n8n-nodes-base.if",
      "typeVersion": 1,
      "position": [1100, 300],
      "parameters": {
        "conditions": {
          "operator": "and",
          "conditions": [
            {
              "key": "{{ $json.route_to }}",
              "operator": "equals",
              "value": "sendgrid_callback_offer"
            }
          ]
        }
      },
      "description": "Check if lead should be routed to email callback offer."
    },
    {
      "id": "retell_create_call",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [1300, 100],
      "parameters": {
        "url": "https://api.retellai.com/v2/create-phone-call",
        "method": "POST",
        "headers": {
          "Authorization": "Bearer {{ env.RETELL_API_KEY }}",
          "Content-Type": "application/json"
        },
        "body": {
          "agent_id": "{{ env.RETELL_VOICE_QUALIFIER_ID }}",
          "phone_number": "{{ $json.phone_number }}",
          "metadata": {
            "lead_id": "{{ $json.external_id }}",
            "name": "{{ $json.name }}",
            "email": "{{ $json.email }}",
            "lead_score": "{{ $json.lead_score }}",
            "procedures": "{{ $json.procedures_interested | join(', ') }}"
          }
        }
      },
      "description": "Create outbound phone call with Retell AI voice agent."
    },
    {
      "id": "supabase_log_retell_call",
      "type": "n8n-nodes-base.postgres",
      "typeVersion": 1,
      "position": [1500, 100],
      "parameters": {
        "host": "${SUPABASE_HOST}",
        "port": 5432,
        "database": "${SUPABASE_DB}",
        "user": "${SUPABASE_USER}",
        "password": "${SUPABASE_PASSWORD}",
        "ssl": true,
        "operation": "executeQuery",
        "query": "INSERT INTO pipeline_events (lead_id, event_type, channel, outcome, metadata, created_at)
        SELECT id, $2, $3, $4, $5, NOW() FROM leads WHERE external_id = $1;",
        "queryParams": [
          "{{ $input[0].json.external_id }}",
          "call_attempted",
          "voice_call",
          "initiated",
          "{{ JSON.stringify({retell_call_id: $json.call_id, phone: $input[0].json.phone_number}) }}"
        ]
      },
      "description": "Log voice call initiation as pipeline event."
    },
    {
      "id": "slack_notify_hot_lead",
      "type": "n8n-nodes-base.slack",
      "typeVersion": 1,
      "position": [1500, 200],
      "parameters": {
        "authentication": "oAuth2",
        "channel": "#hot-leads",
        "text": "Hot Lead Acquired - {{ $input[0].json.name }} ({{ $input[0].json.lead_score }}/100) \\nProcedures: {{ $input[0].json.procedures_interested | join(', ') }}\\nBudget: ${{ $input[0].json.estimated_budget_min }}-${{ $input[0].json.estimated_budget_max }}\\nTimeline: {{ $input[0].json.timeline }}\\n🔴 CALLING NOW",
        "otherOptions": {
          "threadReplyByEmail": false
        }
      },
      "description": "Notify sales team on Slack of hot lead acquisition and voice call initiation."
    },
    {
      "id": "sendgrid_callback_email",
      "type": "n8n-nodes-base.sendGrid",
      "typeVersion": 1,
      "position": [1300, 300],
      "parameters": {
        "templateId": "callback_offer_template",
        "toEmail": "{{ $json.email }}",
        "fromEmail": "hello@cancundentalpartners.com",
        "subject": "Your Personalized Dental Plan - Cancun Dental Partners",
        "dynamicTemplateData": {
          "name": "{{ $json.name }}",
          "procedures": "{{ $json.procedures_interested | join(', ') }}",
          "estimated_savings": "{{ ($json.estimated_budget_max || 5000) * 0.65 | floor }}",
          "callback_link": "https://calendly.com/cancun-dental-partners/consultation?name={{ $json.name }}&email={{ $json.email }}&lead_id={{ $json.external_id }}"
        }
      },
      "description": "Send email callback offer with personalized information packet."
    },
    {
      "id": "twilio_send_sms",
      "type": "n8n-nodes-base.twilio",
      "typeVersion": 1,
      "position": [1300, 200],
      "parameters": {
        "resource": "sms",
        "toNumber": "{{ $json.phone_number }}",
        "message": "Hi {{ $json.name }}! 👋 Thanks for your interest in dental care. Quick question—are you looking at procedures in the next few months? Reply YES or call 1-XXX-DENTAL to chat.",
        "fromNumber": "{{ env.TWILIO_PHONE }}"
      },
      "description": "Send SMS to warm lead to test responsiveness."
    },
    {
      "id": "error_handler",
      "type": "n8n-nodes-base.errorHandler",
      "typeVersion": 1,
      "position": [1700, 250],
      "parameters": {
        "continueOnFail": true,
        "options": {
          "message": "Lead Processing Error",
          "description": "Failed to process lead: {{ $error.message }}"
        }
      },
      "description": "Catch and log any errors in the lead ingestion pipeline."
    },
    {
      "id": "slack_error_notification",
      "type": "n8n-nodes-base.slack",
      "typeVersion": 1,
      "position": [1900, 350],
      "parameters": {
        "authentication": "oAuth2",
        "channel": "#errors",
        "text": "🚨 Lead Ingestion Error\\nLead: {{ $input[0].json.name }}\\nError: {{ $error.message }}\\nTimestamp: {{ now() }}",
        "otherOptions": {}
      },
      "description": "Notify ops team of processing errors."
    }
  ],
  "connections": {
    "webhook_lead_intake": {
      "main": [[{"node": "parse_webhook_body", "type": "main", "index": 0}]]
    },
