      "main": [[{"node": "enrichment_function", "type": "main", "index": 0}]]
    },
    "enrichment_function": {
      "main": [[{"node": "supabase_insert_lead", "type": "main", "index": 0}, {"node": "check_routing_rules", "type": "main", "index": 0}]]
    },
    "supabase_insert_lead": {
      "main": [[{"node": "supabase_insert_consent", "type": "main", "index": 0}]]
    },
    "supabase_insert_consent": {
      "main": [[{"node": "check_routing_rules", "type": "main", "index": 0}]]
    },
    "check_routing_rules": {
      "main": [[{"node": "condition_route_hot", "type": "main", "index": 0}, {"node": "condition_route_sms", "type": "main", "index": 0}, {"node": "condition_route_email", "type": "main", "index": 0}]]
    },
    "condition_route_hot": {
      "main": [[{"node": "retell_create_call", "type": "main", "index": 0}]],
      "main_err": [[{"node": "slack_notify_hot_lead", "type": "main", "index": 0}]]
    },
    "condition_route_sms": {
      "main": [[{"node": "twilio_send_sms", "type": "main", "index": 0}]]
    },
    "condition_route_email": {
      "main": [[{"node": "sendgrid_callback_email", "type": "main", "index": 0}]]
    },
    "retell_create_call": {
      "main": [[{"node": "supabase_log_retell_call", "type": "main", "index": 0}, {"node": "slack_notify_hot_lead", "type": "main", "index": 0}]]
    },
    "supabase_log_retell_call": {
      "main": [[{"node": "error_handler", "type": "main", "index": 0}]]
    },
    "sendgrid_callback_email": {
      "main": [[{"node": "error_handler", "type": "main", "index": 0}]]
    },
    "twilio_send_sms": {
      "main": [[{"node": "error_handler", "type": "main", "index": 0}]]
